import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import Layout from './components/layout/Layout';
import PrivateRoute from './components/layout/PrivateRoute';

// Pages
import BookingList from './pages/Bookings/BookingList';
import BookingForm from './pages/Bookings/BookingForm';
import BookingApproval from './pages/Bookings/BookingApproval';

// Simple Login Component (for demo)
const Login = () => {
  const { login } = useAuth();
  
  const handleLogin = (role) => {
    if (role === 'admin') {
      login('admin@campus.com', 'Admin User', 'ADMIN');
    } else {
      login('john@campus.com', 'John Doe', 'USER');
    }
  };

  return (
    <div className="login-container">
      <h1>Smart Campus Hub</h1>
      <div className="login-buttons">
        <button onClick={() => handleLogin('user')}>Login as User</button>
        <button onClick={() => handleLogin('admin')}>Login as Admin</button>
      </div>
    </div>
  );
};

function AppRoutes() {
  const { isAdmin } = useAuth();

  return (
    <Routes>
      <Route path="/login" element={<Login />} />
      <Route element={<PrivateRoute />}>
        <Route element={<Layout />}>
          <Route path="/" element={<Navigate to="/bookings" />} />
          <Route path="/bookings" element={<BookingList />} />
          <Route path="/bookings/new" element={<BookingForm />} />
          {isAdmin() && (
            <Route path="/admin/bookings" element={<BookingApproval />} />
          )}
        </Route>
      </Route>
    </Routes>
  );
}

function App() {
  return (
    <AuthProvider>
      <Router>
        <AppRoutes />
      </Router>
    </AuthProvider>
  );
}

export default App;
